window.chineseSwitcher={twContent:null,cnContent:null,converter:null,init:function(){window.OpenCC?(this.converter=OpenCC.Converter({from:"tw",to:"cn"}),this.initSwitcher()):(console.log("等待 OpenCC 載入..."),setTimeout(()=>this.init(),100))},initSwitcher:function(){const t=document.querySelector("article");if(!t)return;this.twContent=t.innerHTML;const n=document.querySelector('[data-lang="zh-tw"]'),e=document.querySelector('[data-lang="zh-cn"]');if(!n||!e)return;e.addEventListener("click",()=>{if(e.classList.contains("active"))return;if(n.classList.contains("active")&&(this.twContent=t.innerHTML),!this.cnContent){const e=document.createElement("div");e.innerHTML=this.twContent,e.querySelectorAll(".bookmark-highlight").forEach(e=>{const t=e.textContent;e.parentNode.replaceChild(document.createTextNode(t),e)});const t=e.innerHTML;this.cnContent=this.converter(t)}t.innerHTML=this.cnContent,window.bookmark&&window.bookmark.loadHighlights(),e.classList.add("active"),n.classList.remove("active"),localStorage.setItem("preferredChinese","cn")}),n.addEventListener("click",()=>{if(n.classList.contains("active"))return;e.classList.contains("active")&&(this.cnContent=t.innerHTML),t.innerHTML=this.twContent,window.bookmark&&window.bookmark.loadHighlights(),n.classList.add("active"),e.classList.remove("active"),localStorage.setItem("preferredChinese","tw")});const s=localStorage.getItem("preferredChinese");s==="cn"&&setTimeout(()=>e.click(),100),console.log("繁簡切換初始化完成")},updateContent:function(e,t){e==="tw"?this.twContent=t:e==="cn"&&(this.cnContent=t),console.log(`${e} 內容已更新`)}}